def gen(rng, size):
    ops = ['BrowserHistory']
    args = [['home.test']]
    for i in range(max(1, size)):
        r = rng.random()
        if r < 0.5:
            ops.append('visit')
            args.append(['p%d.test' % i])
        elif r < 0.75:
            ops.append('back')
            args.append([rng.randint(1, 5)])
        else:
            ops.append('forward')
            args.append([rng.randint(1, 5)])
    return [ops, args]

